package main

import (
    "fmt"
    "strings"
)

// stores known addresses from ADKv1 mesh, plus dummy transaction log for fast address-find.

var knownAddrs = make(map[string]string) // known addresses
var knownTrxs = make(map[string]string) // known addresses (transaction hash)
var knownBundles = make(map[string]string) // known knownBundles (transaction hash)
var knownAddrsBundle = make(map[string]string) // known addresses (transaction hash)

func IsKnownAddress(addr string)(bool) {
    if (len(addr) < 81) {
      return false
    }
    addr = addr[:81]
    _, addrExists := knownAddrs[addr]
    return addrExists
}

func IsKnownBundle(bund string)(bool) {
    if (len(bund) < 81) {
      return false
    }
    bund = bund[:81]
    _, bundExists := knownBundles[bund]
    return bundExists
}

func IsKnownTransaction(trx string)(bool) {
    if (len(trx) < 81) {
      return false
    }
    trx = trx[:81]
    _, trxExists := knownTrxs[trx]
    return trxExists
}

func getTransactionForTrxHash(trx string) (string){
  trs9 :=   "";

  addr := knownTrxs[trx]

  if (len(addr) < 81){
    return ""
  }

  bundle := knownAddrsBundle[addr[:81]]
  trxdata := trs9[:2187]+addr[:81]+trs9[2268:2349]+bundle+trs9[2349+81:]
  return (trxdata)
}

func getTransactionHashForAddress(addr string) (string){
  if (len(addr) < 81){
    return ""
  }
  addr_81 := addr[:81]
  return knownAddrs[addr_81]
}

func getTransactionHashForBundle(bund string) (string){
  if (len(bund) < 81){
    return ""
  }
  bund_81 := bund[:81]
  return knownBundles[bund_81]
}

func initAddrs() {
   fmt.Println("Initializing known addresses lookup...")
   knA := strings.Fields(knownAddressesStr)
   knT := strings.Fields(knownAddressesTransactions)
   knB := strings.Fields(knownBundleStr)
   knownAddrs  = make(map[string]string) // known addresses
   cnt := 0
   for idx , element := range knA {
       if (len(element)==81 || len(element)==90){
         cnt++
         knownAddrs[element] = knT[idx] // store address
         knownTrxs[knT[idx]] = element // store transaction
         knownBundles[knB[idx]] = knT[idx] // store bundle
         knownAddrsBundle[element] = knB[idx] // lookup bundle for address
       }
   }

   fmt.Printf("Initializing known addresses lookup complete. Loaded: %v known addresses from ADKv1 mesh. \n", cnt)
}
